Jangan asal load environment variable. Kebocoran konfigurasi adalah penyebab utama kompromi server. Kelas berikut memaksa validasi tipe, pengecekan izin file, dan masking otomatis untuk data sensitif.

### `SecureEnvManager` Class

```python
import os
import stat
import warnings
from typing import Any, Dict, List, Optional, Union
from pathlib import Path

class SecureEnvManager:
    def __init__(self, env_file: Optional[str] = ".env", strict: bool = True):
        self._data: Dict[str, str] = {}
        self._secrets: List[str] = ["PASSWORD", "SECRET", "KEY", "TOKEN", "PRIVATE"]
        self.strict = strict

        if env_file:
            self._load_env_file(env_file)

        self._load_os_env()

    def _check_file_permissions(self, path: Path) -> None:
        """Pastikan file .env tidak bisa dibaca oleh user lain (chmod 600)."""
        if not path.exists():
            if self.strict:
                raise FileNotFoundError(f"SecureEnvManager: File {path} tidak ditemukan.")
            return

        if os.name == "posix":  # Linux/Unix
            file_stat = path.stat()
            mode = file_stat.st_mode & 0o777
            if mode > 0o600:
                raise PermissionError(
                    f"SecureEnvManager: Izin file {path} terlalu longgar ({oct(mode)}). "
                    "Harus 0o600. Jalankan: chmod 600 .env"
                )

    def _load_env_file(self, env_file: str) -> None:
        path = Path(env_file).resolve()
        self._check_file_permissions(path)

        # Parsing manual untuk menghindari dependensi eksternal yang tidak perlu
        # atau gunakan python-dotenv dengan validasi tambahan
        try:
            with open(path, "r") as f:
                for line in f:
                    line = line.strip()
                    if not line or line.startswith("#"):
                        continue
                    if "=" in line:
                        key, value = line.split("=", 1)
                        self._data[key.strip()] = value.strip().strip('"').strip("'")
        except Exception as e:
            raise RuntimeError(f"Gagal memuat file env: {e}")

    def _load_os_env(self) -> None:
        """OS env overriding file env adalah standar keamanan."""
        for key, value in os.environ.items():
            self._data[key] = value

    def get(self, key: str, default: Any = None, cast: type = str) -> Any:
        value = self._data.get(key, default)

        if value is None and self.strict:
            raise ValueError(f"SecureEnvManager: Variable wajib '{key}' tidak ditemukan.")

        if value is None:
            return default

        try:
            if cast == bool:
                return value.lower() in ["true", "1", "yes"]
            return cast(value)
        except ValueError:
            raise TypeError(f"Gagal cast '{key}' ke {cast.__name__}")

    def __repr__(self) -> str:
        """Mencegah kebocoran secret saat logging/print."""
        safe_data = {}
        for k, v in self._data.items():
            if any(secret in k.upper() for secret in self._secrets):
                safe_data[k] = "***REDACTED***"
            else:
                safe_data[k] = v
        return f"<SecureEnvManager config={safe_data}>"

# Contoh Penggunaan
if __name__ == "__main__":
    try:
        config = SecureEnvManager(env_file=".env", strict=True)

        DB_HOST = config.get("DB_HOST", cast=str)
        DB_PORT = config.get("DB_PORT", cast=int)
        API_KEY = config.get("API_KEY") # Akan di-redact jika di-print

        print(config) 
    except (PermissionError, ValueError, FileNotFoundError) as e:
        print(f"[CRITICAL] {e}")
```

### Poin Keamanan Implementasi Ini:

1.  **Enforcement Izin File (`_check_file_permissions`)**:
    *   Pada sistem Linux/Unix, script akan menolak load jika `.env` bisa dibaca oleh user lain (selain owner). Ini mencegah leak via user lain di server yang sama.
    *   Perbaiki izin segera: `chmod 600 .env`.

2.  **Masking Otomatis (`__repr__`)**:
    *   Mencegah accidental logging. Jika Anda tidak sengaja `print(config)` atau log object ini, password/key akan muncul sebagai `***REDACTED***`.
    *   Deteksi keyword sensitif: `PASSWORD`, `SECRET`, `KEY`, `TOKEN`.

3.  **Strict Mode**:
    *   Jika `strict=True`, aplikasi akan crash saat startup jika variabel wajib hilang. Lebih baik fail early daripada runtime error di produksi.

4.  **Prioritas Environment OS**:
    *   Variabel dari `os.environ` menimpa isi file `.env`. Ini penting untuk deployment Docker/Kubernetes dimana secret di-inject via orchestrator, bukan file.

### Peringatan Operasional:
*   **Jangan commit `.env`**: Pastikan `.env` ada di `.gitignore`.
*   **Validasi Input**: Jika nilai env digunakan untuk query SQL atau path file, tetap lakukan sanitasi terpisah. Env var bukan satu-satunya lapisan pertahanan.
*   **Produksi**: Gunakan secrets manager (AWS Secrets Manager, HashiCorp Vault) untuk skala besar. File `.env` hanya untuk development atau deployment sederhana.

## Observer Pattern Implementation in Python

Implementasi lengkap Observer pattern dengan pendekatan modern Python:

```python
from abc import ABC, abstractmethod
from typing import List, Any


class Observer(ABC):
    """Interface untuk Observer"""

    @abstractmethod
    def update(self, subject: 'Subject', *args: Any, **kwargs: Any) -> None:
        """Method yang dipanggil saat subject berubah"""
        pass


class Subject:
    """Subject/Observable yang mengelola daftar observer"""

    def __init__(self) -> None:
        self._observers: List[Observer] = []
        self._state: Any = None

    def attach(self, observer: Observer) -> None:
        """Menambahkan observer ke daftar"""
        if observer not in self._observers:
            self._observers.append(observer)

    def detach(self, observer: Observer) -> None:
        """Menghapus observer dari daftar"""
        try:
            self._observers.remove(observer)
        except ValueError:
            pass

    def notify(self, *args: Any, **kwargs: Any) -> None:
        """Memberitahu semua observer tentang perubahan"""
        for observer in self._observers:
            observer.update(self, *args, **kwargs)

    @property
    def state(self) -> Any:
        return self._state

    @state.setter
    def state(self, value: Any) -> None:
        self._state = value
        self.notify()


# ============================================
# Concrete Implementations
# ============================================

class EmailNotificationObserver(Observer):
    """Observer untuk mengirim notifikasi email"""

    def __init__(self, email: str) -> None:
        self.email = email

    def update(self, subject: Subject, *args: Any, **kwargs: Any) -> None:
        print(f"[EMAIL] Sending to {self.email}: State changed to {subject.state}")


class LogObserver(Observer):
    """Observer untuk logging perubahan"""

    def __init__(self, log_file: str = "app.log") -> None:
        self.log_file = log_file

    def update(self, subject: Subject, *args: Any, **kwargs: Any) -> None:
        print(f"[LOG] {subject.state} written to {self.log_file}")


class CacheInvalidationObserver(Observer):
    """Observer untuk invalidate cache"""

    def __init__(self, cache_keys: List[str]) -> None:
        self.cache_keys = cache_keys

    def update(self, subject: Subject, *args: Any, **kwargs: Any) -> None:
        print(f"[CACHE] Invalidating keys: {self.cache_keys}")


# ============================================
# Usage Example
# ============================================

if __name__ == "__main__":
    # Create subject
    user_data = Subject()

    # Create observers
    email_observer = EmailNotificationObserver("admin@example.com")
    log_observer = LogObserver("user_changes.log")
    cache_observer = CacheInvalidationObserver(["user_profile", "user_session"])

    # Attach observers
    user_data.attach(email_observer)
    user_data.attach(log_observer)
    user_data.attach(cache_observer)

    # Trigger state changes
    print("=== Changing State ===")
    user_data.state = {"user_id": 1, "action": "update"}

    print("\n=== Detaching Log Observer ===")
    user_data.detach(log_observer)
    user_data.state = {"user_id": 1, "action": "delete"}
```

